// Get all known installation names for the dropdown
export const BAH_INSTALLATIONS = Object.keys(INSTALLATION_MHA_MAP).sort();

// Get BAH rate for a given installation and pay grade
export function getBAHRate(installationName, payGrade, withDependents) {
  const mha = INSTALLATION_MHA_MAP[installationName];
  if (!mha) return null;
  const rates = MHA_RATES[mha];
  if (!rates) return null;
  const idx = BAH_PAY_GRADES.indexOf(payGrade);
  if (idx === -1) return null;
  return withDependents ? rates[idx][0] : rates[idx][1];
}

export function getMHAForInstallation(installationName) {
  return INSTALLATION_MHA_MAP[installationName] || null;
}

export function isOCONUS(installationName) {
  const oconusKeywords = ['Korea','Germany','Japan','Italy','Guam','Okinawa','Cuba','Bahrain','Kuwait','Qatar','Djibouti','Humphreys','Daegu','Yongsan','Ramstein','Kaiserslautern','Spangdahlem','Wiesbaden','Grafenwoehr','Vilseck','Baumholder','Ansbach','Stuttgart','Torii','Kadena','Misawa','Camp Zama','Yokosuka','Sasebo','Naples','Vicenza','Aviano','Sigonella','Rota','Moron','Incirlik','NSA Bahrain','Lemonier'];
  return oconusKeywords.some(kw => installationName.includes(kw));
}

export function formatCurrencyBAH(amount) {
  if (amount === null || amount === undefined) return '—';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(amount);
}

